cors_config.code:
// middleware.ts or API route:
const ALLOWED_ORIGINS = [
  process.env.NEXT_PUBLIC_APP_URL,
  'https://yourdomain.com',
].filter(Boolean);

function getCorsHeaders(origin: string | null) {
  const headers: Record<string, string> = {
    'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  };
  if (origin && ALLOWED_ORIGINS.includes(origin)) {
    headers['Access-Control-Allow-Origin'] = origin;
  }
  return headers;
}

input_sanitizer.code:
// lib/validations.ts
export function validateStringField(value: unknown, name: string, opts?: { min?: number; max?: number; required?: boolean }): string | null {
  const { min = 0, max = 1000, required = true } = opts || {};
  if (value === undefined || value === null || value === '') {
    return required ? `${name} is required` : null;
  }
  if (typeof value !== 'string') return `${name} must be a string`;
  if (value.length < min) return `${name} must be at least ${min} characters`;
  if (value.length > max) return `${name} must be at most ${max} characters`;
  return null;
}

csrf_protection.code:
// lib/csrf.ts
import { randomBytes } from 'crypto';

export function generateCsrfToken(): string {
  return randomBytes(32).toString('hex');
}

export function validateCsrfToken(cookieToken: string | undefined, headerToken: string | undefined): boolean {
  if (!cookieToken || !headerToken) return false;
  return cookieToken === headerToken;
}
